def flatten_nested_dict(d, sep='.'):
    """Flatten a nested dict into a single-level dict with compound keys."""
    result = {}
    for key, value in d.items():
        if isinstance(value, dict):
            for sub_key, sub_value in flatten_nested_dict(value, sep).items():
                result[f"{key}{sep}{sub_key}"] = sub_value
        else:
            result[key] = value
    return result
